import{_ as a}from"./chunks/10.BK-UJDBz.js";import{_ as s,C as o,o as i,c as n,al as t,E as l}from"./chunks/framework.BJsoK6mY.js";const d="/assets/8.BKwVhH5i.webp",p="/assets/9.Cg6n9S86.webp",h="/assets/11.BCx6kYh5.webp",c="/assets/12.GSllsNaS.webp",u="/assets/13.8cCzKX7k.webp",m="/assets/14.BRJZbNGk.webp",P=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"minecraft/server/detailed-guide/plugins.md","filePath":"en/minecraft/server/detailed-guide/plugins.md","lastUpdated":null}'),g={name:"minecraft/server/detailed-guide/plugins.md"};function f(w,e,y,b,v,k){const r=o("VpFolderTree");return i(),n("div",null,[e[0]||(e[0]=t('<h3 id="installing-plugins" tabindex="-1">Installing plugins <a class="header-anchor" href="#installing-plugins" aria-label="Permalink to &quot;Installing plugins&quot;">​</a></h3><p>After we first started the server, a <code>plugins</code> folder was automatically created in our server folder. This is now the part where working with a Paper server really becomes fun. You can download any plugin from the internet that is compatible with your version and drop it directly into this <code>plugins</code> folder.</p><p>After adding a new plugin make sure to <mark>restart the server</mark>. Alternatively use the command <code>/reload</code> but please be aware that a clean restart is always safer and better.</p><h4 id="where-to-download-plugins" tabindex="-1">Where to download plugins <a class="header-anchor" href="#where-to-download-plugins" aria-label="Permalink to &quot;Where to download plugins&quot;">​</a></h4><p>Before we continue you need to understand that their are other plugin platforms besides PaperMC. These platforms like Spigot and CraftBucket had been the norm for many years since the earliest years of the game. But since around 2018 / 2019 many server owners switched form Spigot to PaperMC because of performance benefits.</p><p>If you want to install mods you need to make sure that they are compatible with our platform, in this case <code>PaperMC</code>.</p><p>But here is the twist: <code>PaperMC</code> was originally developed as a fork of Spigot, meaning they essentially started as a copy of Spigot until the PaperMC developers started adding their own features that where not present in Spigot.<br> Until Minecraft <code>1.21.4</code> the Paper team tried to keep Spigot Plugins compatible with Paper as well, but since then they dropped that support. This means that at this point, as long as your server runs on <code>1.21.4</code> or older, there are still many Spigot plugins out there that even though they officially don&#39;t support Paper run just fine.</p><p>In general there are 2 main website most people use if they want to browse for plugins</p><div style="display:flex;flex-direction:row;gap:16px;align-items:flex-start;"><div style="width:50%;"><p><a href="https://www.spigotmc.org/resources/categories/spigot.4/?order=download_count" target="_blank" rel="noreferrer">SpigotMC</a></p><img src="'+d+'" alt="SpigotMC - the OG Plugin Forum"><p>SpigotMC has been around for an eternity (2012!) and has for many years been pretty much the place to be if you want to publish your own plugin. Unfortunately there is no filter for plugins that are compatible with PaperMC so you will have to filter for Spigot and prey that it just works.</p></div><div style="width:50%;"><p><a href="https://modrinth.com/discover/plugins?g=categories:paper&amp;s=downloads" target="_blank" rel="noreferrer">Modrinth</a> <code>Recommended</code><br></p><img src="'+p+'" style="width:100%;" alt="Modrinth Plugin Homepage"><p>Starting in 2020 Modrinth quite literally changed the game. They are an open-source modding and plugin platform. They also offer their own launcher, Modrinth App. The offer a far better experience than SpigotMC by having: A better UI, more filters and a larger library of mods and plugins!</p></div></div><hr><h4 id="example-downloading-essentialsx-from-modrinth" tabindex="-1">Example: Downloading EssentialsX from Modrinth <a class="header-anchor" href="#example-downloading-essentialsx-from-modrinth" aria-label="Permalink to &quot;Example: Downloading EssentialsX from Modrinth&quot;">​</a></h4><p>When searching for Plugins make sure to set filters for Paper and your server&#39;s Minecraft version.</p><div style="display:flex;width:50%;flex-direction:row;gap:16px;align-items:flex-start;"><img src="'+a+'" style="width:50%;" alt="Modrinth Game Version Filter"><img src="'+h+'" style="width:50%;" alt="Modrinth Loader Filter"></div><p>For this example I choose the plugin <a href="https://modrinth.com/plugin/essentialsx" target="_blank" rel="noreferrer"><code>EssentialsX</code></a> which is a pretty well know for adding a bunch of very useful commands like: <code>/sethome, /home, /tpa, /fly, /rules</code> etc.<br> You can find a full list <a href="https://essentialsx.net/commands" target="_blank" rel="noreferrer">here</a></p><a href="https://modrinth.com/plugin/essentialsx" target="_blank" rel="noopener"><img src="'+c+'" alt="Example" class="no-viewer"></a><p>Click on the <code>Versions</code> tab. Here you can once again filter all the different released versions of this plugin. Make sure to find a version that supports Paper in the <code>Platforms</code> row and includes your minecraft version under <code>Game versions</code></p><img src="'+u+'" style="width:100%;" alt="Modrinth Plugin Version Tab &amp; Filtering"><p>If you found the perfect version, click the green download button on the right.</p><p>As you might have guess this downloaded file now needs to go into our <code>plugins</code> folder. In the end your server should look like this:</p>',19)),l(r,{data:[{name:"Paper Server",isFolder:!0,children:[{name:"cache",isFolder:!0,children:[],open:!1,locked:!0},{name:"libraries",isFolder:!0,children:[],open:!1,locked:!0},{name:"logs",isFolder:!0,children:[],open:!1,locked:!0},{name:"plugins",isFolder:!0,children:[{name:"EssentialsX.jar",isFolder:!1},{name:"...",isFolder:!1}],open:!0},{name:"versions",isFolder:!0,children:[],open:!1,locked:!0},{name:"eula.txt",isFolder:!1},{name:"server.jar",isFolder:!1},{name:"server.properties",isFolder:!1},{name:"start.bat",isFolder:!1}]}],"default-open":!0,"show-toolbar":!1,"show-badges":!0,interactive:!0}),e[1]||(e[1]=t('<p>Don&#39;t worry if your plugin name is different, the only thing that matters is that we move the <code>.jar</code> file into our <code>plugins</code> folder.</p><p>Now restart the server.</p><hr><p>Some plugins send a log to the console once they get loaded during server start up. The EssentialsX Plugin for example prints this line during startup:</p><div class="language-log vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">log</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">22:44:49</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;"> INFO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]: [Essentials] Enabling Essentials </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">v2.21.2</span></span></code></pre></div><div style="display:flex;flex-direction:row;gap:16px;align-items:flex-start;"><div style="width:40%;"><p>Once you join the server you should see a welcome message from Essentials and should be able to perform commands like <code>/help</code></p><p>You can install every other plugin in the exact same way.</p></div><img src="'+m+'" style="width:60%;" alt="EssentialX Commands"></div>',6))])}const C=s(g,[["render",f]]);export{P as __pageData,C as default};
